import { useToast } from 'vuestic-ui'
import { axiosInstance } from '../../../services/api'

const { notify } = useToast()

/**
 * 更新訂單使用者的內部備註名稱
 * 直接調用 PATCH /user/{id} 端點
 */
export const updateOrderUserInternalRemarkName = async (params: { id: number; internalRemarkName: string | null }) => {
    try {
        const { id, internalRemarkName } = params
        await axiosInstance.patch(`/user/${id}`, { internalRemarkName })
        notify({
            message: '通訊暱稱已更新',
            duration: 2000,
        })
    } catch (error) {
        console.error('Failed to update user internal remark name:', error)
        notify({
            message: '更新通訊暱稱失敗',
            color: 'danger',
            duration: 3000,
        })
        throw error
    }
}

export const useOrderUsers = () => {
    return {
        updateOrderUserInternalRemarkName,
    }
}
