export type UserRole = 'admin' | 'user' | 'owner'
type BaseEntity = {
    createdAt: string
    updatedAt: string
    deletedAt: string | null
}
export interface Order extends BaseEntity {
    id: number
    type: ServiceCategoryBackend
    orderPlanId: number
    orderPlanTableName: string
    paymentId: null
    userInfoId: number
    status: OrderStatus
    frontendStep: number
    payment: Payment[]
}
export type BaseOrder = BaseEntity & {
    id: number
    orderPlanId: number
    orderPlanTableName: string
    userInfoId: number
    status: string
    frontendStep: number
    manualOperationStatus: OrderManualOperationStatus
    payment: Payment[]
    userInfo: UserInfo
}
export type OrderPlanMassage = BaseEntity & {
    id: number
    planId: number
    time: string
    secondTime?: string
    selectedTherapists?: number[]
    hotelAddress?: string
    hotelImageFileNames?: string[]
    hotelImageUrls: string[]
    needHotelBooking: boolean
    note?: string
    confirmedTherapistId: number | null
    confirmedTime: string | null
}
export type OrderPlanMassageSnapshot = BaseEntity & {
    id: number
    orderId: number
    name: string
    quoteExpiredTime?: string
    prePaymentAmount: number
    totalAmount: number
}
export type OrderPlanCharterSnapshot = BaseEntity & {
    id: number
    orderId: number
    name: string
    option: any[]
    quoteExpiredTime: string | number | null
    prePaymentAmount: number
    totalAmount: number
}
export type OrderPlanCharter = BaseEntity & {
    id: number
    planId: number
    carId: number
    time: string
    days: number
    packageId: number
    passengerNumber: number
    pickupLocation: string
    dropOffLocation: string
    travelPlanNote: string
}
export type CharterOrder = BaseOrder & {
    type: 'plan_charter'
    orderPlanCharter: OrderPlanCharter
    orderPlanCharterSnapshot: OrderPlanCharterSnapshot
}
export type OrderPlanShuttle = BaseEntity & {
    id: number
    planId: number
    areaId: number
    carId: number
    direction: string
    time: string
    passengerNumber: number
    customLocation: string
    hotelName: string
    passengerName: string
    flightNumber: string
    flightArrivalTime: string
    largeLuggageAmount: number
    smallLuggageAmount: number
    flightType: string
    buyFastPass: boolean
    note: string
}
export type OrderPlanShuttleSnapshot = BaseEntity & {
    id: number
    orderId: number
    name: string
    direction: string
    option: any[]
    quoteExpiredTime: string | number | null
    prePaymentAmount: number
    totalAmount: number
}
export type ShuttleOrder = BaseOrder & {
    type: 'plan_shuttle'
    orderPlanShuttle: OrderPlanShuttle
    orderPlanShuttleSnapshot: OrderPlanShuttleSnapshot
}
export type OrderPlanEscortSnapshot = BaseEntity & {
    id: number
    orderId: number
    minServiceHours: number
    minAttractions: number
    maxAttractions: number
    pricePerHour: number
    basePrice: number
    hoursBeforeBooking: number | null
    serviceTimeType: string
    fixedServiceStartTime: string | null
    firstServiceStartTime: string | null
    lastServiceStartTime: string | null
    bookingDeposit: number
    bookingDepositType: string
    fixedBookingDeposit: number
    bookingDepositPerHour: number
    extraAmount: number
    allowVehicles: string[]
    imageUrl: string | null
    prePaymentAmount: number
    totalAmount: number
    quoteExpiredTime: string | number | null
    holdHandsPrice: number
}
export type EscortOrder = BaseOrder & {
    type: 'plan_escort'
    orderPlanEscort: OrderPlanEscort
    orderPlanEscortSnapshot: OrderPlanEscortSnapshot
}
export type MassageOrder = BaseOrder & {
    type: 'plan_dragon_massage'
    orderPlanDragonMassage: OrderPlanMassage
    orderPlanDragonMassageSnapshot: OrderPlanMassageSnapshot
}
export type OrderPlanTutorSnapshot = BaseEntity & {
    id: number
    orderId: number
    name: string
    packageId: number
    packagePrice: number
    quoteExpiredTime: string | number | null
    prePaymentAmount: number
    totalAmount: number
}
export type OrderPlanTutor = BaseEntity & {
    id: number
    planId: number
    packageId: number
    startTime: string
    teacherIds: number[] | null
    address: string | null
    confirmedTeacherId: number | null
    package: {
        createdAt: string
        updatedAt: string
        deletedAt: string | null
        id: number
        name: string
        earliestServiceStartTime: string
        latestServiceStartTime: string
        price: number
        prePaymentAmount: number
        serviceHours: number
    }
    teachers: Teacher[]
}
export type Teacher = {
    createdAt: string
    updatedAt: string
    deletedAt: string | null
    id: number
    number: number
    coverImage: string
    images: string[]
    height: number
    weight: number
    birthYear: number
    sortOrder: number
    isActive: boolean
}
export type TutorOrder = BaseOrder & {
    type: 'plan_tutor'
    orderPlanTutor: OrderPlanTutor
    orderPlanTutorSnapshot: OrderPlanTutorSnapshot
}
export type OrderPlanCustomQuote = BaseEntity & {
    id: number
    planId: number
    quoteAmount: number
    note: string | null
    remark: string | null
}
export type OrderCustomQuoteSnapshot = BaseEntity & {
    id: number
    orderId: number
    name: string
    quoteExpiredTime: string | number | null
    prePaymentAmount: number
    totalAmount: number
}
export type QuoteOrder = BaseOrder & {
    type: 'plan_custom_quote'
    orderPlanCustomQuote: OrderPlanCustomQuote
    orderCustomQuoteSnapshot: OrderCustomQuoteSnapshot
}
export type VnOrder = CharterOrder | ShuttleOrder | EscortOrder | MassageOrder | TutorOrder | QuoteOrder
export interface OrderWithPlanEscort extends Order {
    orderPlanEscort: OrderPlanEscort
}
export interface OrderWithPlanEscortAndUserInfo extends OrderWithPlanEscort {
    userInfo: UserInfo
}
interface OrderPlanEscort extends BaseEntity {
    id: number
    planId: number
    serviceHours: string
    numGuides: number
    numTourists: number
    startTime: string
    vehicle: EscortVehicle
    guideDress: EscortDress | null
    guideExpectIds: string | null // 期望導遊id, 逗號分隔
    attractionIds: string | null // 期望景點id, 逗號分隔
    customAttraction: string | null
    meetAddress: string | undefined
    note: string | undefined
    guideAssignedIds: number[] | null
    needHoldHands: boolean
}
export const EscortVehicle = {
    SCOOTER: 'scooter',
    DO_DO_CAR: 'do_do_car',
    TAXI: 'taxi',
} as const

export type EscortVehicle = (typeof EscortVehicle)[keyof typeof EscortVehicle]
export const EscortDress = {
    NORMAL: 'normal',
    AO_DAI: 'ao_dai',
} as const

export type EscortDress = (typeof EscortDress)[keyof typeof EscortDress]
export const OrderStatus = {
    INITIAL: 'initial',
    PAYMENT: 'payment',
    PAYMENT_FAIL: 'payment_fail',
    COMPLETED: 'completed',
    CANCEL: 'cancel',
    CANCEL_COMPLETED: 'cancel_completed',
} as const

export type OrderStatus = (typeof OrderStatus)[keyof typeof OrderStatus]
export const ServiceCategoryBackend = {
    ESCORT: 'plan_escort',
    SHUTTLE: 'plan_shuttle',
    CHARTER: 'plan_charter',
    MASSAGE: 'plan_dragon_massage',
    TUTOR: 'plan_tutor',
    QUOTE: 'plan_custom_quote',
} as const

export type ServiceCategoryBackend = (typeof ServiceCategoryBackend)[keyof typeof ServiceCategoryBackend]

export type Payment = BaseEntity & {
    id: number
    orderPaymentId: string
    ecpayOrderId?: string
    ecpayStatus?: string | null
    amount?: number
    status?: PaymentStatus
    couponCode?: string
    discountAmount?: string
    type: PaymentType
}
export interface UserInfo extends BaseEntity {
    id: number
    firstName: string
    lastName: null | string
    nickname: null | string
    internalRemarkName: null | string
    profileUrl: null | string
    email: string
    firebaseUid: string
    referralCode: string
    phone: BaseEntity & {
        id: number
        userInfoId: number
        code: string
        phoneNumber: string
    }
    socialMedia: SocalMedia[]
}
export interface SocalMedia extends BaseEntity {
    id: number
    userInfoId: number
    type: string
    accountId: string
}

/// enum
export const PaymentStatus = {
    INITIAL: 'initial',
    COMPLETED: 'completed',
    FAILED: 'failed',
    EXPIRED: 'expired',
    REFUND: 'refund',
} as const
export type PaymentStatus = (typeof PaymentStatus)[keyof typeof PaymentStatus]

export const PaymentType = {
    VOIN_PAYMENT: 'vcoin_payment',
    ECPAY_PAYMENT: 'payment',
    COUPON_PAYMENT: 'coupon_payment',
} as const
export type PaymentType = (typeof PaymentType)[keyof typeof PaymentType]

export const OrderManualOperationStatus = {
    PENDING: 'pending',
    PROCESSED: 'processed',
} as const
export type OrderManualOperationStatus = (typeof OrderManualOperationStatus)[keyof typeof OrderManualOperationStatus]

export const OrderType = {
    PlanEscort: 'plan_escort',
    PlanShuttle: 'plan_shuttle',
    PlanCharter: 'plan_charter',
    PlanMassage: 'plan_dragon_massage',
    PlanTutor: 'plan_tutor',
} as const
export type OrderType = (typeof OrderType)[keyof typeof OrderType]
