import { Ref, ref, unref, watch } from 'vue'
import { type Filters, Pagination, Sorting } from '../../../data/pages/orders'
import { ServiceCategoryBackend, Order, EscortOrder, VnOrder } from '../types'
import { watchIgnorable } from '@vueuse/core'
import { useFormat } from '../../../composables/useFormat'
import { DateTime } from 'luxon'
import { usePublicStore } from '../../../stores/public-store'
import api from '../../../services/api'
const publicStore = usePublicStore()
const { formatDate } = useFormat()
const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })
const makeSortingRef = () => ref<Sorting>({ sortBy: 'createdAt', sortingOrder: null })
const makeFiltersRef = () => ref<Partial<Filters>>({ isActive: true, search: '' })
export const categorys: { [key in ServiceCategoryBackend]: string } = {
    [ServiceCategoryBackend.ESCORT]: '奧黛導遊',
    [ServiceCategoryBackend.SHUTTLE]: '機場接送',
    [ServiceCategoryBackend.CHARTER]: '包車旅遊',
    [ServiceCategoryBackend.MASSAGE]: '龍筋按摩',
    [ServiceCategoryBackend.TUTOR]: '越語家教',
    [ServiceCategoryBackend.QUOTE]: '自訂訂單',
}
export const useOrders = (options?: {
    pagination?: Ref<Pagination>
    sorting?: Ref<Sorting>
    filters?: Ref<Partial<Filters>>
}) => {
    const isLoading = ref(false)
    const orders = ref<VnOrder[]>([])

    const { filters = makeFiltersRef(), sorting = makeSortingRef(), pagination = makePaginationRef() } = options || {}

    const fetch = async () => {
        isLoading.value = true
        // const { data, pagination: newPagination } = await getUsers({
        //     ...unref(filters),
        //     ...unref(sorting),
        //     ...unref(pagination),
        // })
        const params = {
            ...unref(filters),
            sortBy: sorting.value.sortBy,
            sortOrder: sorting.value.sortingOrder,
            offset: (pagination.value.page - 1) * pagination.value.perPage,
            limit: pagination.value.perPage,
            ...(filters.value.isActive && { excludeStatus: 'initial' }),
            ...(!filters.value.isActive && { status: 'initial' }),
        }
        const { data } = await api.getOrders(params)
        orders.value = data.data
        const newPagination = { page: pagination.value.page, perPage: 10, total: data.total }
        ignoreUpdates(() => {
            pagination.value = newPagination
        })

        isLoading.value = false
    }

    const { ignoreUpdates } = watchIgnorable([pagination, sorting], fetch, { deep: true })

    watch(
        filters,
        () => {
            // Reset pagination to first page when filters changed
            pagination.value.page = 1
            fetch()
        },
        { deep: true },
    )

    fetch()

    const getServiceDate = (order: EscortOrder) => {
        return formatDate(Number(order.orderPlanEscort.startTime))
    }
    const getServiceDuring = (order: EscortOrder) => {
        const startTime = DateTime.fromMillis(Number(order.orderPlanEscort.startTime), { zone: 'Asia/Ho_Chi_Minh' })
        const endTime = startTime.plus({ hours: Number(order.orderPlanEscort.serviceHours) })
        return `${startTime.toFormat('HH:mm')} - ${endTime.toFormat('HH:mm')}`
    }
    const getGuideExpect = (order: EscortOrder) => {
        return order.orderPlanEscort.guideExpectIds
            ?.split(',')
            .map((id) => publicStore.guides.find((escort) => escort.id === Number(id))?.name)
            .join(', ')
    }
    const getAttractions = (order: EscortOrder) => {
        return order.orderPlanEscort.attractionIds
            ?.split(',')
            .map((id) => publicStore.attractions.find((attraction) => attraction.id === Number(id))?.name)
            .join(', ')
    }
    return {
        categorys,
        isLoading,

        filters,
        sorting,
        pagination,

        orders,

        fetch,

        getServiceDate,
        getServiceDuring,
        getGuideExpect,
        getAttractions,
        async add(order: Order) {
            // isLoading.value = true
            // await addUser(user)
            // await fetch()
            // isLoading.value = false
            console.log('add order', order)
        },

        async update(order: Order) {
            // isLoading.value = true
            // await updateUser(user)
            // await fetch()
            // isLoading.value = false
            console.log('update order', order)
        },

        async remove(order: Order) {
            // isLoading.value = true
            // await removeUser(user)
            // await fetch()
            // isLoading.value = false
            console.log('remove order', order)
        },
    }
}
