<script setup lang="ts">
import { PropType, computed, ref } from 'vue'
import { CharterOrder } from '../types'
import { useFormat } from '../../../composables/useFormat'
import { useOrders } from '../composables/useOrders'
import { useCharterOrders } from '../composables/useCharterOrders'
import { OrderManualOperationStatus } from '../types'
import { useOrderUsers } from '../composables/useOrderUsers'
import api from '../../../services/api'
import OrderContactInfoSection from './OrderContactInfoSection.vue'
const { formatDate } = useFormat()
const { categorys } = useOrders()
const { getStartTime } = useCharterOrders()
const { updateOrderUserInternalRemarkName } = useOrderUsers()
const planIdNameMap: { [key in number]: string } = {
    1: '包車旅遊',
}
const carIdToNameMap: { [key in number]: string } = {
    1: '經濟五座',
    2: '尊爵五座',
    3: '經濟七座',
    4: '商務七座',
    5: '尊爵七座',
    6: '商務九座',
    7: '多人巴士',
}
const packageIdToNameMap: { [key in number]: string } = {
    1: '4hr/50km',
    2: '4hr/100km',
    3: '8hr/100km',
    4: '8hr/200km',
    5: '10hr/100km',
    6: '10hr/300km',
}

const manualOperationStatus = [
    {
        text: '待處理',
        value: OrderManualOperationStatus.PENDING,
    },
    {
        text: '已處理',
        value: OrderManualOperationStatus.PROCESSED,
    },
]
const props = defineProps({
    order: {
        type: Object as PropType<CharterOrder>,
        required: true,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const defaultOrder = {
    id: -1,
    manualOperationStatus: 'pending' as OrderManualOperationStatus,
    createdAt: '',
    category: '',
    plan: '',
    cardName: '',
    days: 0,
    packageName: '',
    serviceDate: '',
    serviceDuring: '',
    passengerNumber: 0,
    pickupLocation: '',
    dropOffLocation: '',
    travelPlanNote: '',
}

const order = computed(() => {
    if (!props.order) {
        return defaultOrder
    }
    const createdAt = formatDate(Number(props.order.orderPlanCharter.createdAt))

    return {
        id: props.order.id,
        manualOperationStatus: props.order.manualOperationStatus,
        createdAt,
        category: categorys[props.order.type],
        plan: planIdNameMap[props.order.orderPlanCharter.planId],
        cardName: carIdToNameMap[props.order.orderPlanCharter.carId],
        days: props.order.orderPlanCharter.days,
        packageName: packageIdToNameMap[props.order.orderPlanCharter.packageId],
        serviceDate: formatDate(Number(props.order.orderPlanCharter.time)),
        serviceDuring: getStartTime(props.order),
        passengerNumber: props.order.orderPlanCharter.passengerNumber,
        pickupLocation: props.order.orderPlanCharter.pickupLocation,
        dropOffLocation: props.order.orderPlanCharter.dropOffLocation,
        travelPlanNote: props.order.orderPlanCharter.travelPlanNote,
    }
})
const userInfo = computed(() => {
    const lineId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'line')?.accountId
    const wechatId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'wechat')?.accountId
    const telegramId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'telegram')
        ?.accountId
    const zaloId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'zalo')?.accountId
    return {
        userId: props.order.userInfo.id,
        firstName: props.order.userInfo.firstName,
        internalRemarkName: props.order.userInfo.internalRemarkName,
        email: props.order.userInfo.email,
        phone: props.order.userInfo.phone?.phoneNumber,
        phoneCode: props.order.userInfo.phone?.code,
        lineId,
        wechatId,
        telegramId,
        zaloId,
    }
})
const internalRemarkName = ref(props.order.userInfo.internalRemarkName)
const emit = defineEmits(['close', 'save'])

const onSave = async () => {
    if (internalRemarkName.value !== props.order.userInfo.internalRemarkName) {
        await updateOrderUserInternalRemarkName({
            id: props.order.userInfo.id,
            internalRemarkName: internalRemarkName.value,
        })
    }

    // 只處理操作參數
    api.updateManualOperationStatus({
        orderId: props.order.id,
        manualOperationStatus: order.value.manualOperationStatus,
    })
    emit('save')
}
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="add-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.id"
                    label="訂單編號"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.createdAt"
                    label="下訂時間"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.category"
                    label="訂購項目"
                    class="w-full sm:w-1/2"
                    name="category"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.plan"
                    label="訂購方案"
                    class="w-full sm:w-1/2"
                    name="plan"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.cardName"
                    label="車款"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />

                <VaInput
                    v-model="order.packageName"
                    label="用車方案"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate"
                    label="行程日期"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceDuring"
                    label="起始時間"
                    class="w-full sm:w-1/2"
                    name="serviceDuring"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.days"
                    label="天數"
                    class="w-full sm:w-1/2"
                    name="serviceDuring"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.passengerNumber"
                    label="乘客人數"
                    class="w-full sm:w-1/2"
                    name="numTourists"
                    readonly
                    preset="solid"
                />
            </div>
            <VaTextarea
                v-model="order.pickupLocation"
                label="上車地點"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />
            <VaTextarea
                v-model="order.dropOffLocation"
                label="下車地點"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />
            <VaTextarea
                v-model="order.travelPlanNote"
                label="預計行程路線"
                class="w-full"
                name="note"
                readonly
                preset="solid"
            />
            <OrderContactInfoSection v-model="internalRemarkName" :contact-info="userInfo" />
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單狀態</span></VaDivider>
            <VaSelect
                v-model="order.manualOperationStatus"
                label="操作狀態"
                class="w-full"
                :options="manualOperationStatus"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">結帳資訊</span></VaDivider>
            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
