<script setup lang="ts">
import { computed } from 'vue'
import { useToast } from 'vuestic-ui'

type ContactInfo = {
    userId: number
    firstName?: string | null
    email?: string | null
    phone?: string | null
    phoneCode?: string | null
    lineId?: string | null
    wechatId?: string | null
    telegramId?: string | null
    zaloId?: string | null
}

const props = defineProps<{
    contactInfo: ContactInfo
    modelValue: string | null
}>()

const emit = defineEmits<{
    (event: 'update:modelValue', value: string | null): void
}>()

const { notify } = useToast()

const internalRemarkName = computed({
    get: () => props.modelValue ?? '',
    set: (value: string) => {
        emit('update:modelValue', value || null)
    },
})

const copyText = async (copyContent: string | null | undefined) => {
    if (!copyContent) {
        return
    }

    try {
        await navigator.clipboard.writeText(copyContent)
        notify({
            message: `已複製到剪貼簿: ${copyContent}`,
            duration: 3000,
        })
    } catch (err) {
        alert(`Failed to copy text: ${err}`)
    }
}
</script>

<template>
    <VaDivider class="w-full" orientation="left"><span class="px-2">聯絡資訊</span></VaDivider>
    <div class="flex gap-4 flex-col sm:flex-row w-full">
        <VaInput
            :model-value="contactInfo.firstName || ''"
            label="訂購人"
            class="w-full sm:w-1/2"
            name="firstName"
            readonly
            preset="solid"
        />
        <VaInput
            v-model="internalRemarkName"
            label="通訊暱稱"
            class="w-full sm:w-1/2"
            name="internalRemarkName"
            placeholder="可編輯"
        />
    </div>
    <div class="flex gap-4 flex-col sm:flex-row w-full">
        <VaInput
            :model-value="contactInfo.email || ''"
            label="連絡信箱"
            class="w-full sm:w-1/2"
            name="email"
            readonly
            preset="solid"
        >
            <template #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.email)" />
            </template>
        </VaInput>
        <VaInput
            :model-value="contactInfo.phoneCode || ''"
            label="手機國碼"
            class="w-full sm:w-1/2"
            name="phoneCode"
            readonly
            preset="solid"
        />
    </div>
    <div class="flex gap-4 flex-col sm:flex-row w-full">
        <VaInput
            :model-value="contactInfo.phone || ''"
            label="手機號碼"
            class="w-full sm:w-1/2"
            name="phone"
            readonly
            preset="solid"
        >
            <template #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.phone)" />
            </template>
        </VaInput>
        <VaInput
            :model-value="contactInfo.lineId || ''"
            label="Line ID"
            class="w-full sm:w-1/2"
            name="lineId"
            readonly
            preset="solid"
        >
            <template v-if="contactInfo.lineId" #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.lineId)" />
            </template>
        </VaInput>
    </div>
    <div class="flex gap-4 flex-col sm:flex-row w-full">
        <VaInput
            :model-value="contactInfo.wechatId || ''"
            label="WECHAT ID"
            class="w-full sm:w-1/2"
            name="wechatId"
            readonly
            preset="solid"
        >
            <template v-if="contactInfo.wechatId" #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.wechatId)" />
            </template>
        </VaInput>
        <VaInput
            :model-value="contactInfo.telegramId || ''"
            label="TELEGRAM"
            class="w-full sm:w-1/2"
            name="telegramId"
            readonly
            preset="solid"
        >
            <template v-if="contactInfo.telegramId" #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.telegramId)" />
            </template>
        </VaInput>
    </div>
    <div class="flex gap-4 flex-col sm:flex-row w-full">
        <VaInput
            :model-value="contactInfo.zaloId || ''"
            label="ZALO"
            class="w-full sm:w-1/2"
            name="zaloId"
            readonly
            preset="solid"
        >
            <template v-if="contactInfo.zaloId" #appendInner>
                <VaIcon name="content_copy" color="secondary" @click="() => copyText(contactInfo.zaloId)" />
            </template>
        </VaInput>
    </div>
</template>
