<script setup lang="ts">
import { PropType, computed, onMounted, ref } from 'vue'
import { EscortDress, EscortOrder } from '../types'
import { useFormat } from '../../../composables/useFormat'
import { useOrders } from '../composables/useOrders'
import { usePublicStore } from '../../../stores/public-store'
import { OrderManualOperationStatus } from '../types'
import { useOrderUsers } from '../composables/useOrderUsers'
import api from '../../../services/api'
import { EscortVehicle } from '../../../types/enums'
import OrderContactInfoSection from './OrderContactInfoSection.vue'
const publicStore = usePublicStore()
const { formatDate } = useFormat()
const { categorys, getServiceDate, getServiceDuring, getGuideExpect, getAttractions } = useOrders()
const { updateOrderUserInternalRemarkName } = useOrderUsers()
const planIdNameMap: { [key in number]: string } = {
    1: '東方小巴黎',
    2: '華燈夜生活',
    3: '西貢河船宴',
    4: '韓式桑拿趣',
}
const escortDressTextMap = {
    [EscortDress.NORMAL]: '時裝',
    [EscortDress.AO_DAI]: '奧黛',
}
const vehicleTextMap = {
    [EscortVehicle.SCOOTER]: '機車',
    [EscortVehicle.DO_DO_CAR]: '嘟嘟車',
    [EscortVehicle.TAXI]: 'TAXI',
}
const manualOperationStatus = [
    {
        text: '待處理',
        value: OrderManualOperationStatus.PENDING,
    },
    {
        text: '已處理',
        value: OrderManualOperationStatus.PROCESSED,
    },
]
const props = defineProps({
    order: {
        type: Object as PropType<EscortOrder>,
        required: true,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const defaultOrder = {
    id: -1,
    createdAt: '',
    category: '',
    plan: '',
    serviceDate: '',
    serviceDuring: '',
    numTourists: 0,
    numGuides: 0,
    guideExpect: '',
    guideDress: '',
    attractions: '',
    meetAddress: '',
    note: '',
    manualOperationStatus: OrderManualOperationStatus.PENDING,
    vehicle: '',
    needChineseGuide: '',
}

const order = computed(() => {
    if (!props.order) {
        return defaultOrder
    }
    const createdAt = formatDate(Number(props.order.orderPlanEscort.createdAt))

    return {
        id: props.order.id,
        manualOperationStatus: props.order.manualOperationStatus,
        createdAt,
        category: categorys[props.order.type],
        plan: planIdNameMap[props.order.orderPlanEscort.planId],
        serviceDate: getServiceDate(props.order),
        serviceDuring: getServiceDuring(props.order),
        numTourists: props.order.orderPlanEscort.numTourists,
        numGuides: props.order.orderPlanEscort.numGuides,
        guideExpect: getGuideExpect(props.order),
        guideDress: escortDressTextMap[props.order.orderPlanEscort.guideDress || EscortDress.NORMAL],
        attractions: getAttractions(props.order),
        meetAddress: props.order.orderPlanEscort.meetAddress,
        note: props.order.orderPlanEscort.note,
        vehicle: vehicleTextMap[props.order.orderPlanEscort.vehicle],
        needChineseGuide: props.order.orderPlanEscort.needHoldHands ? '是' : '否',
    }
})
const userInfo = computed(() => {
    const lineId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'line')?.accountId
    const wechatId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'wechat')?.accountId
    const telegramId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'telegram')
        ?.accountId
    const zaloId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'zalo')?.accountId
    return {
        userId: props.order.userInfo.id,
        firstName: props.order.userInfo.firstName,
        internalRemarkName: props.order.userInfo.internalRemarkName,
        email: props.order.userInfo.email,
        phone: props.order.userInfo.phone?.phoneNumber,
        phoneCode: props.order.userInfo.phone?.code,
        lineId,
        wechatId,
        telegramId,
        zaloId,
    }
})
const internalRemarkName = ref(props.order.userInfo.internalRemarkName)
const selectedGuideIds = ref<number[]>([])
const emit = defineEmits(['close', 'save'])

const onSave = async () => {
    // if (form.validate()) {
    if (internalRemarkName.value !== props.order.userInfo.internalRemarkName) {
        await updateOrderUserInternalRemarkName({
            id: props.order.userInfo.id,
            internalRemarkName: internalRemarkName.value,
        })
    }

    if (selectedGuideIds.value.length > 0) {
        if (props.order.orderPlanEscort.guideAssignedIds?.join('') !== selectedGuideIds.value.join('')) {
            const params = {
                orderId: props.order.id,
                guideIds: selectedGuideIds.value,
            }
            await api.assignGuidesToOrder(params)
        }
    }
    if (order.value.meetAddress !== props.order.orderPlanEscort.meetAddress) {
        const params = {
            orderId: props.order.id,
            planParams: {
                meetAddress: order.value.meetAddress,
            },
        }
        await api.updateEscortOrder(params)
    }
    api.updateManualOperationStatus({
        orderId: props.order.id,
        manualOperationStatus: order.value.manualOperationStatus,
    })
    emit('save')
    // }
}

const guides = computed(() => {
    return publicStore.guides
        .filter((guide) => guide.isActive)
        .map((guide) => ({
            text: guide.name,
            value: guide.id,
        }))
})
onMounted(() => {
    selectedGuideIds.value = props.order.orderPlanEscort.guideAssignedIds || []
    if (!publicStore.guides.length) {
        publicStore.getAllGuides()
    }
})
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="add-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.id"
                    label="訂單編號"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.createdAt"
                    label="下訂時間"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.category"
                    label="訂購項目"
                    class="w-full sm:w-1/2"
                    name="category"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.plan"
                    label="訂購方案"
                    class="w-full sm:w-1/2"
                    name="plan"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate"
                    label="行程日期"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceDuring"
                    label="行程時段"
                    class="w-full sm:w-1/2"
                    name="serviceDuring"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.numTourists"
                    label="遊客人數"
                    class="w-full sm:w-1/2"
                    name="numTourists"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.numGuides"
                    label="導遊人數"
                    class="w-full sm:w-1/2"
                    name="numGuides"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.guideExpect"
                    label="導遊偏好"
                    class="w-full sm:w-1/2"
                    name="guideExpect"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.guideDress"
                    label="導遊穿著"
                    class="w-full sm:w-1/2"
                    name="guideDress"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.vehicle"
                    label="交通工具"
                    class="w-full sm:w-1/2"
                    name="guideExpect"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.needChineseGuide"
                    label="是否指定中文導遊"
                    class="w-full sm:w-1/2"
                    name="guideDress"
                    readonly
                    preset="solid"
                />
            </div>
            <VaSelect
                v-model="selectedGuideIds"
                label="導遊指派"
                class="w-full"
                :options="guides"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
                multiple
            />
            <VaInput
                v-model="order.attractions"
                label="景點偏好"
                class="w-full"
                name="attractions"
                readonly
                preset="solid"
            />

            <VaTextarea v-model="order.meetAddress" label="會合地址" class="w-full" name="meetAddress" />

            <VaTextarea v-model="order.note" label="訂單備註" class="w-full" name="note" readonly preset="solid" />

            <OrderContactInfoSection v-model="internalRemarkName" :contact-info="userInfo" />
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單狀態</span></VaDivider>
            <VaSelect
                v-model="order.manualOperationStatus"
                label="操作狀態"
                class="w-full"
                :options="manualOperationStatus"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">結帳資訊</span></VaDivider>
            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
