<script setup lang="ts">
import { PropType, computed, onMounted, ref } from 'vue'
import { MassageOrder } from '../types'
import { usePublicStore } from '../../../stores/public-store'
import { useFormat } from '../../../composables/useFormat'
import { useOrders } from '../composables/useOrders'
import { useMassageOrders } from '../composables/useMassageOrders'
import { OrderManualOperationStatus } from '../types'
import { DateTime } from 'luxon'
import { useOrderUsers } from '../composables/useOrderUsers'
import api from '../../../services/api'
import OrderContactInfoSection from './OrderContactInfoSection.vue'
const { formatDate, formatDateV } = useFormat()
const { categorys } = useOrders()
const { getStartTime, getStartTime2 } = useMassageOrders()
const { updateOrderUserInternalRemarkName } = useOrderUsers()
const publicStore = usePublicStore()
const planIdNameMap: { [key in number]: string } = {
    1: '龍筋按摩',
}
const manualOperationStatus = [
    {
        text: '待處理',
        value: OrderManualOperationStatus.PENDING,
    },
    {
        text: '已處理',
        value: OrderManualOperationStatus.PROCESSED,
    },
]
const props = defineProps({
    order: {
        type: Object as PropType<MassageOrder>,
        required: true,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const defaultOrder = {
    id: -1,
    createdAt: '',
    category: '',
    plan: '',
    serviceDate: '',
    serviceStartTime: '',
    note: '',
    serviceDate2: '',
    serviceStartTime2: '',
    hotelAddress: '',
    needHotelBooking: '',
    manualOperationStatus: OrderManualOperationStatus.PENDING,
    hotelImageUrls: [] as string[],
    confirmedTherapistId: null,
    selectedTherapists: '',
    confirmedTime: '',
}

const order = computed(() => {
    if (!props.order) {
        return defaultOrder
    }
    const createdAt = formatDate(Number(props.order.orderPlanDragonMassage.createdAt))

    return {
        id: props.order.id,
        manualOperationStatus: props.order.manualOperationStatus,
        createdAt,
        category: categorys[props.order.type],
        plan: planIdNameMap[props.order.orderPlanDragonMassage.planId],
        selectedTherapists: getSelectedTherapists(props.order.orderPlanDragonMassage.selectedTherapists || []),
        serviceDate: formatDateV(Number(props.order.orderPlanDragonMassage.time)),
        serviceStartTime: getStartTime(props.order),
        serviceDate2: formatDateV(Number(props.order.orderPlanDragonMassage.secondTime)),
        serviceStartTime2: getStartTime2(props.order),
        hotelAddress: props.order.orderPlanDragonMassage.hotelAddress,
        note: props.order.orderPlanDragonMassage.note,
        needHotelBooking: props.order.orderPlanDragonMassage.needHotelBooking ? '是' : '否',
        hotelImageUrls: props.order.orderPlanDragonMassage.hotelImageUrls || [],
        confirmedTherapistId: props.order.orderPlanDragonMassage.confirmedTherapistId || null,
        confirmedTime: props.order.orderPlanDragonMassage.confirmedTime || '',
    }
})
const getSelectedTherapists = (selectedTherapists: number[]) => {
    return selectedTherapists
        .map((id) => {
            const therapist = publicStore.therapists.find((t) => t.id === id)
            return therapist ? `${therapist.number}.${therapist.name}` : `未知導遊(id:${id})`
        })
        .join(', ')
}
const userInfo = computed(() => {
    const lineId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'line')?.accountId
    const wechatId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'wechat')?.accountId
    const telegramId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'telegram')
        ?.accountId
    const zaloId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'zalo')?.accountId
    return {
        userId: props.order.userInfo.id,
        firstName: props.order.userInfo.firstName,
        internalRemarkName: props.order.userInfo.internalRemarkName,
        email: props.order.userInfo.email,
        phone: props.order.userInfo.phone?.phoneNumber,
        phoneCode: props.order.userInfo.phone?.code,
        lineId,
        wechatId,
        telegramId,
        zaloId,
    }
})
const internalRemarkName = ref(props.order.userInfo.internalRemarkName)
const emit = defineEmits(['close', 'save'])

const onSave = async () => {
    if (internalRemarkName.value !== props.order.userInfo.internalRemarkName) {
        await updateOrderUserInternalRemarkName({
            id: props.order.userInfo.id,
            internalRemarkName: internalRemarkName.value,
        })
    }

    // 處理操作參數
    if (props.order.manualOperationStatus !== order.value.manualOperationStatus) {
        await api.updateManualOperationStatus({
            orderId: props.order.id,
            manualOperationStatus: order.value.manualOperationStatus,
        })
    }
    if (
        props.order.orderPlanDragonMassage.confirmedTherapistId !== confirmedTherapistId.value ||
        confirmedTime.value !== props.order.orderPlanDragonMassage.confirmedTime
    ) {
        // 決定要保存的確認時間值
        let timeToSave = confirmedTime.value
        if (confirmedTime.value === 'custom' && customDate.value && customTime.value) {
            // 參考提供的方式組合日期和時間
            const date = DateTime.fromJSDate(customDate.value).toFormat('yyyy-MM-dd')
            const time = DateTime.fromJSDate(customTime.value).toFormat('HH:mm')
            const timeString = `${date} ${time}`
            const timestemp = DateTime.fromFormat(timeString, 'yyyy-MM-dd HH:mm', {
                zone: 'Asia/Ho_Chi_Minh',
            }).toMillis()
            timeToSave = timestemp.toString()
        }

        await api.updateMassageOrder({
            orderId: props.order.id,
            planParams: {
                confirmedTherapistId: confirmedTherapistId.value,
                confirmedTime: timeToSave,
            },
        })
    }

    emit('save')
}

onMounted(() => {
    // 初始化已確認的導遊ID
    confirmedTherapistId.value = order.value.confirmedTherapistId || null

    // 初始化確認時間
    const orderConfirmedTime = order.value.confirmedTime || ''
    if (orderConfirmedTime) {
        // 檢查是否是預設的時間選項
        const isDefaultOption =
            orderConfirmedTime === props.order.orderPlanDragonMassage.time ||
            orderConfirmedTime === props.order.orderPlanDragonMassage.secondTime

        if (isDefaultOption) {
            confirmedTime.value = orderConfirmedTime
        } else {
            // 如果是自訂時間，設定為 custom 並分別填入日期和時間選擇器
            confirmedTime.value = 'custom'
            const dt = DateTime.fromMillis(Number(orderConfirmedTime), { zone: 'Asia/Ho_Chi_Minh' })
            // 創建對應越南時間的 Date 物件，避免瀏覽器自動轉換時區
            const year = dt.year
            const month = dt.month - 1 // JavaScript Date 的月份是 0-11
            const day = dt.day
            const hour = dt.hour
            const minute = dt.minute

            customDate.value = new Date(year, month, day)
            customTime.value = new Date(2000, 0, 1, hour, minute) // 使用固定日期，只取時間部分
        }
    }
})

const openImage = (imageUrl: string) => {
    window.open(imageUrl, '_blank')
}

const handleImageError = (event: Event) => {
    const target = event.target as HTMLImageElement
    if (target) {
        target.style.display = 'none'
    }
}

// 時間確認選項
const timeOptions = computed(() => {
    if (!props.order) return []

    const options = []
    const { formatDateTimeV } = useFormat()

    // 第一個時間選項
    if (props.order.orderPlanDragonMassage.time) {
        options.push({
            text: `時間 1: ${formatDateTimeV(Number(props.order.orderPlanDragonMassage.time))}`,
            value: props.order.orderPlanDragonMassage.time,
        })
    }

    // 第二個時間選項
    if (props.order.orderPlanDragonMassage.secondTime) {
        options.push({
            text: `時間 2: ${formatDateTimeV(Number(props.order.orderPlanDragonMassage.secondTime))}`,
            value: props.order.orderPlanDragonMassage.secondTime,
        })
    }

    // 第三個時間選項（自訂時間）
    let customText = '自訂時間'
    if (confirmedTime.value === 'custom' && customDate.value && customTime.value) {
        // 組合自訂時間並顯示
        const date = DateTime.fromJSDate(customDate.value).toFormat('yyyy-MM-dd')
        const time = DateTime.fromJSDate(customTime.value).toFormat('HH:mm')
        customText = `自訂時間: ${date} ${time}`
    }

    options.push({
        text: customText,
        value: 'custom',
    })

    return options
})

// 自訂時間相關的響應式變數
const customDate = ref(new Date())
const customTime = ref(new Date())
const showCustomDateTime = computed(() => confirmedTime.value === 'custom')

// 監聽自訂日期和時間變化，僅觸發 UI 更新
const handleCustomDateTimeChange = () => {
    // 這裡不需要做任何處理，只是觸發響應式更新
    // 實際的時間轉換會在 onSave 時進行
}

const therapists = computed(() => {
    return publicStore.therapists
        .filter((therapist) => therapist.isActive)
        .map((therapist) => ({
            text: `${therapist.number}.${therapist.name}`,
            value: therapist.id,
        }))
})
const confirmedTherapistId = ref<number | null>(null)
const confirmedTime = ref<string>('')
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="add-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.id"
                    label="訂單編號"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.createdAt"
                    label="下訂時間"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.category"
                    label="訂購項目"
                    class="w-full sm:w-1/2"
                    name="category"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.plan"
                    label="訂購方案"
                    class="w-full sm:w-1/2"
                    name="plan"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate"
                    label="預約日期"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceStartTime"
                    label="起始時間"
                    class="w-full sm:w-1/2"
                    name="serviceStartTime"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate2"
                    label="預約日期2"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceStartTime2"
                    label="起始時間2"
                    class="w-full sm:w-1/2"
                    name="serviceStartTime"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.selectedTherapists"
                    label="技師偏好"
                    class="w-full"
                    name="guideExpect"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.needHotelBooking"
                    label="代訂旅店"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
            </div>
            <VaTextarea
                v-model="order.hotelAddress"
                label="旅店地址"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />

            <!-- 旅店圖片展示區域 -->
            <div v-if="order.hotelImageUrls && order.hotelImageUrls.length > 0" class="w-full">
                <div class="mb-2 text-sm font-medium text-gray-700">旅店圖片</div>
                <div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                    <div
                        v-for="(imageUrl, index) in order.hotelImageUrls"
                        :key="index"
                        class="relative aspect-square overflow-hidden rounded-lg border border-gray-200 hover:shadow-md transition-shadow cursor-pointer"
                        @click="openImage(imageUrl)"
                    >
                        <img
                            :src="imageUrl"
                            :alt="`旅店圖片 ${index + 1}`"
                            class="w-full h-full object-cover"
                            loading="lazy"
                            @error="handleImageError"
                        />
                    </div>
                </div>
            </div>
            <VaTextarea
                v-model="order.note"
                label="訂單備註"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">管理確認區</span></VaDivider>
            <div class="w-full">
                <VaSelect
                    v-model="confirmedTherapistId"
                    label="龍筋老師指派"
                    class="w-full"
                    :options="therapists"
                    name="projects"
                    text-by="text"
                    track-by="value"
                    value-by="value"
                    placeholder="未指派"
                />
                <VaSelect
                    v-model="confirmedTime"
                    label="時間確認"
                    class="w-full mt-4"
                    :options="timeOptions"
                    name="confirmedTime"
                    text-by="text"
                    track-by="value"
                    value-by="value"
                    placeholder="請選擇確認時間"
                    clearable
                />
                <!-- 自訂時間選擇器 -->
                <div v-if="showCustomDateTime" class="w-full mt-4">
                    <div class="flex gap-4 flex-col sm:flex-row w-full">
                        <VaDateInput
                            v-model="customDate"
                            label="自訂日期"
                            class="w-full sm:w-1/2"
                            placeholder="請選擇日期"
                            clearable
                            @input="handleCustomDateTimeChange"
                        />
                        <VaTimeInput
                            v-model="customTime"
                            label="自訂時間"
                            class="w-full sm:w-1/2"
                            placeholder="請選擇時間"
                            clearable
                            @input="handleCustomDateTimeChange"
                        />
                    </div>
                    <div class="text-sm text-gray-600 mt-1">* 時間將以越南時區保存</div>
                </div>
            </div>
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單狀態</span></VaDivider>
            <VaSelect
                v-model="order.manualOperationStatus"
                label="操作狀態"
                class="w-full"
                :options="manualOperationStatus"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
            />
            <OrderContactInfoSection v-model="internalRemarkName" :contact-info="userInfo" />
            <VaDivider class="w-full" orientation="left"><span class="px-2">結帳資訊</span></VaDivider>
            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
